import React, { useState } from 'react';
import axios from 'axios';

const TrainModel = () => {
  const [numClasses, setNumClasses] = useState(0);
  const [images, setImages] = useState([]);
  const [message, setMessage] = useState('');

  const handleImageUpload = (event) => {
    setImages([...event.target.files]);
  };

  const handleSubmit = async () => {
    const formData = new FormData();
    formData.append('numClasses', numClasses);
    images.forEach(image => formData.append('images', image));

    try {
      const response = await axios.post('/api/train', formData, {
        headers: {
          'Content-Type': 'multipart/form-data'
        }
      });
      setMessage(response.data.message);
    } catch (error) {
      setMessage('Error training model');
    }
  };

  return (
    <div>
      <h1>Train Your Model</h1>
      <input type="number" onChange={(e) => setNumClasses(e.target.value)} placeholder="Number of classes" />
      <input type="file" multiple onChange={handleImageUpload} />
      <button onClick={handleSubmit}>Train Model</button>
      <p>{message}</p>
    </div>
  );
};

export default TrainModel;
